const query = $.input.query || '';
const searchQuery = query + ' API data real-time';
return { searchQuery };

const results = $.steps.findDataSources.response.results || [];
let bestUrl = '';
let sourceInfo = [];
results.forEach((r, i) => {
  sourceInfo.push({ rank: i + 1, title: r.title || '', url: r.url, snippet: (r.text || '').slice(0, 150) });
  if (!bestUrl && r.url) bestUrl = r.url;
});
return { bestUrl, sourceInfo, sourceCount: results.length };

const md = ($.steps.scrapeSource.response.data || {}).markdown || '';
const query = $.input.query;
const sources = $.steps.pickBestSource.output.sourceInfo || [];
let sourcesText = '';
sources.forEach(s => { sourcesText += s.rank + '. ' + s.title + ' (' + s.url + ')
'; });

const prompt = 'You are a data extraction specialist. A user asked: "' + query + '"

I found these data sources:
' + sourcesText + '

Scraped content from the best source:
' + md.slice(0, 4000) + '

Extract the specific data the user asked for. Return ONLY valid JSON:
{
  "query": "original query",
  "answer": "direct answer to the query",
  "dataPoints": [{ "label": "metric name", "value": "metric value", "unit": "if applicable" }],
  "source": "source URL",
  "confidence": "high/medium/low",
  "additionalContext": "any helpful extra info",
  "lastUpdated": "when the data was last updated if known"
}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, dataPoints: [], confidence: 'low' }; }

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'API Data Fetch Results', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Query:* ' + (ai.query || $.input.query) } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer:*\n' + (ai.answer || 'No answer generated') } });

if (ai.dataPoints && ai.dataPoints.length > 0) {
  let dpText = '*Data Points:*\n';
  ai.dataPoints.forEach(dp => {
    dpText += '- *' + dp.label + ':* ' + dp.value + (dp.unit ? ' ' + dp.unit : '') + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: dpText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Source: ' + (ai.source || 'N/A') + ' | Confidence: ' + (ai.confidence || 'N/A') }] });

const fallback = 'Data fetch: ' + (ai.answer || '').slice(0, 200);
return { blocks, fallback };
